import{_ as e,X as i,Y as c,a1 as o}from"./framework-dc96d9cf.js";const l={},r=o('<h1 id="对synchroized的一些认识" tabindex="-1"><a class="header-anchor" href="#对synchroized的一些认识" aria-hidden="true">#</a> 对synchroized的一些认识</h1><blockquote><p>synchroized块可以保证块中的代码在同一时刻只能让一个线程访问，其他尝试进入代码块的线程都会被阻塞，直到代码块中的线程执行完。</p></blockquote><p>synchroized可以修饰以下不同的块</p><ul><li>实例方法</li><li>静态方法</li><li>实例方法中的代码块</li><li>静态方法中的代码块</li></ul><p>synchroized关键字修饰实例方法和实例对象时，锁住的是对象，而修饰静态方法和静态方法中的代码块时，锁住的是该类的类对象。</p><p>synchroized支持重入，并具有继承性，具体表现形式有两种：</p><ul><li>a，b方法同时被同一把锁修饰，a方法中可以执行b方法</li><li>子类可以执行父类方法</li></ul>',7),n=[r];function s(t,a){return i(),c("div",null,n)}const d=e(l,[["render",s],["__file","对synchroized的一些认识.html.vue"]]);export{d as default};
